18	pub fn parse(
19	    globalThis: *jsc.JSGlobalObject,
20	    callframe: *jsc.CallFrame,
21	) bun.JSError!jsc.JSValue {
22	    var arena = bun.ArenaAllocator.init(globalThis.allocator());
23	    const allocator = arena.allocator();
24	    defer arena.deinit();
25	
26	    var ast_memory_allocator = bun.handleOom(allocator.create(ast.ASTMemoryAllocator));
27	    var ast_scope = ast_memory_allocator.enter(allocator);
28	    defer ast_scope.exit();
29	
30	    var log = logger.Log.init(default_allocator);
31	    const arguments = callframe.arguments_old(1).slice();
32	    if (arguments.len == 0 or arguments[0].isEmptyOrUndefinedOrNull()) {
33	        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
34	    }
35	
36	    var input_slice = try arguments[0].toSlice(globalThis, bun.default_allocator);
37	    defer input_slice.deinit();
38	    const source = &logger.Source.initPathString("input.toml", input_slice.slice());
39	    const parse_result = TOML.parse(source, &log, allocator, false) catch |err| {
40	        if (err == error.StackOverflow) {
41	            return globalThis.throwStackOverflow();
42	        }
43	        return globalThis.throwValue(try log.toJS(globalThis, default_allocator, "Failed to parse toml"));
44	    };
45	
46	    // for now...
47	    const buffer_writer = js_printer.BufferWriter.init(allocator);
48	    var writer = js_printer.BufferPrinter.init(buffer_writer);
49	    _ = js_printer.printJSON(
50	        *js_printer.BufferPrinter,
51	        &writer,
52	        parse_result,
53	        source,
54	        .{
55	            .mangled_props = null,
56	        },
57	    ) catch {
58	        return globalThis.throwValue(try log.toJS(globalThis, default_allocator, "Failed to print toml"));
59	    };
60	
61	    const slice = writer.ctx.buffer.slice();
62	    var out = bun.String.borrowUTF8(slice);
63	    defer out.deref();
64	
65	    return out.toJSByParseJSON(globalThis);
66	}
