61	const Stringifier = struct {
62	    stack_check: bun.StackCheck,
63	    builder: wtf.StringBuilder,
64	    indent: usize,
65	
66	    known_collections: std.AutoHashMap(JSValue, AnchorAlias),
67	    array_item_counter: usize,
68	    prop_names: bun.StringHashMap(usize),
69	
70	    space: Space,
71	
72	    pub const Space = union(enum) {
73	        minified,
74	        number: u32,
75	        str: String,
76	
77	        pub fn init(global: *JSGlobalObject, space_value: JSValue) JSError!Space {
78	            const space = try space_value.unwrapBoxedPrimitive(global);
79	            if (space.isNumber()) {
80	                // Clamp on the float to match the spec's min(10, ToIntegerOrInfinity(space)).
81	                // toInt32() wraps large values and Infinity to 0, which is wrong.
82	                const num_f = space.asNumber();
83	                if (!(num_f >= 1)) return .minified; // handles NaN, -Infinity, 0, negatives
84	                return .{ .number = if (num_f > 10) 10 else @intFromFloat(num_f) };
85	            }
86	
87	            if (space.isString()) {
88	                const str = try space.toBunString(global);
89	                if (str.length() == 0) {
90	                    str.deref();
91	                    return .minified;
92	                }
93	                return .{ .str = str };
94	            }
95	
96	            return .minified;
97	        }
98	
99	        pub fn deinit(this: *const Space) void {
100	            switch (this.*) {
101	                .minified => {},
102	                .number => {},
103	                .str => |str| {
104	                    str.deref();
105	                },
106	            }
107	        }
108	    };
109	
110	    const AnchorOrigin = enum {
111	        root,
112	        array_item,
113	        prop_value,
114	    };
115	
116	    const AnchorAlias = struct {
117	        anchored: bool,
118	        used: bool,
119	        name: Name,
120	
121	        pub fn init(origin: ValueOrigin) AnchorAlias {
122	            return .{
123	                .anchored = false,
124	                .used = false,
125	                .name = switch (origin) {
126	                    .root => .root,
127	                    .array_item => .{ .array_item = 0 },
128	                    .prop_value => .{ .prop_value = .{ .prop_name = origin.prop_value, .counter = 0 } },
129	                },
130	            };
131	        }
132	
133	        pub const Name = union(AnchorOrigin) {
134	            // only one root anchor is possible
135	            root,
136	            array_item: usize,
137	            prop_value: struct {
138	                prop_name: String,
139	                // added after the name
140	                counter: usize,
141	            },
142	        };
143	    };
144	
145	    pub fn init(allocator: std.mem.Allocator, global: *JSGlobalObject, space_value: JSValue) JSError!Stringifier {
146	        var prop_names: bun.StringHashMap(usize) = .init(allocator);
147	        // always rename anchors named "root" to avoid collision with
148	        // root anchor/alias
149	        try prop_names.put("root", 0);
150	
151	        return .{
152	            .stack_check = .init(),
153	            .builder = .init(),
154	            .indent = 0,
155	            .known_collections = .init(allocator),
156	            .array_item_counter = 0,
157	            .prop_names = prop_names,
158	            .space = try .init(global, space_value),
159	        };
160	    }
161	
162	    pub fn deinit(this: *Stringifier) void {
163	        this.builder.deinit();
164	        this.known_collections.deinit();
165	        this.prop_names.deinit();
166	        this.space.deinit();
167	    }
168	
169	    const ValueOrigin = union(AnchorOrigin) {
170	        root,
171	        array_item,
172	        prop_value: String,
173	    };
174	
175	    pub fn findAnchorsAndAliases(this: *Stringifier, global: *JSGlobalObject, value: JSValue, origin: ValueOrigin) StringifyError!void {
176	        if (!this.stack_check.isSafeToRecurse()) {
177	            return error.StackOverflow;
178	        }
179	
180	        const unwrapped = try value.unwrapBoxedPrimitive(global);
181	
182	        if (unwrapped.isNull()) {
183	            return;
184	        }
185	
186	        if (unwrapped.isNumber()) {
187	            return;
188	        }
189	
190	        if (unwrapped.isBigInt()) {
191	            return global.throw("YAML.stringify cannot serialize BigInt", .{});
192	        }
193	
194	        if (unwrapped.isBoolean()) {
195	            return;
196	        }
197	
198	        if (unwrapped.isString()) {
199	            return;
200	        }
201	
202	        if (comptime Environment.ci_assert) {
203	            bun.assertWithLocation(unwrapped.isObject(), @src());
204	        }
205	
206	        const object_entry = try this.known_collections.getOrPut(unwrapped);
207	        if (object_entry.found_existing) {
208	            // this will become an alias. increment counters here because
209	            // now the anchor/alias is confirmed used.
210	
211	            if (object_entry.value_ptr.used) {
212	                return;
213	            }
214	
215	            object_entry.value_ptr.used = true;
216	
217	            switch (object_entry.value_ptr.name) {
218	                .root => {
219	                    // only one possible
220	                },
221	                .array_item => |*counter| {
222	                    counter.* = this.array_item_counter;
223	                    this.array_item_counter += 1;
224	                },
225	                .prop_value => |*prop_value| {
226	                    const name_entry = try this.prop_names.getOrPut(prop_value.prop_name.byteSlice());
227	                    if (name_entry.found_existing) {
228	                        name_entry.value_ptr.* += 1;
229	                    } else {
230	                        name_entry.value_ptr.* = 0;
231	                    }
232	
233	                    prop_value.counter = name_entry.value_ptr.*;
234	                },
235	            }
236	            return;
237	        }
238	
239	        object_entry.value_ptr.* = .init(origin);
240	
241	        if (unwrapped.isArray()) {
242	            var iter = try unwrapped.arrayIterator(global);
243	            while (try iter.next()) |item| {
244	                if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
245	                    continue;
246	                }
247	
248	                try this.findAnchorsAndAliases(global, item, .array_item);
249	            }
250	            return;
251	        }
252	
253	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
254	            global,
255	            try unwrapped.toObject(global),
256	        );
257	        defer iter.deinit();
258	
259	        while (try iter.next()) |prop_name| {
260	            if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
261	                continue;
262	            }
263	            try this.findAnchorsAndAliases(global, iter.value, .{ .prop_value = prop_name });
264	        }
265	    }
266	
267	    const StringifyError = JSError || bun.StackOverflow;
268	
269	    pub fn stringify(this: *Stringifier, global: *JSGlobalObject, value: JSValue) StringifyError!void {
270	        if (!this.stack_check.isSafeToRecurse()) {
271	            return error.StackOverflow;
272	        }
273	
274	        const unwrapped = try value.unwrapBoxedPrimitive(global);
275	
276	        if (unwrapped.isNull()) {
277	            this.builder.append(.latin1, "null");
278	            return;
279	        }
280	
281	        if (unwrapped.isNumber()) {
282	            if (unwrapped.isInt32()) {
283	                this.builder.append(.int, unwrapped.asInt32());
284	                return;
285	            }
286	
287	            const num = unwrapped.asNumber();
288	            if (std.math.isNegativeInf(num)) {
289	                this.builder.append(.latin1, "-.inf");
290	                // } else if (std.math.isPositiveInf(num)) {
291	                //     builder.append(.latin1, "+.inf");
292	            } else if (std.math.isInf(num)) {
293	                this.builder.append(.latin1, ".inf");
294	            } else if (std.math.isNan(num)) {
295	                this.builder.append(.latin1, ".nan");
296	            } else if (std.math.isNegativeZero(num)) {
297	                this.builder.append(.latin1, "-0");
298	            } else if (std.math.isPositiveZero(num)) {
299	                this.builder.append(.latin1, "+0");
300	            } else {
301	                this.builder.append(.double, num);
302	            }
303	            return;
304	        }
305	
306	        if (unwrapped.isBigInt()) {
307	            return global.throw("YAML.stringify cannot serialize BigInt", .{});
308	        }
309	
310	        if (unwrapped.isBoolean()) {
311	            if (unwrapped.asBoolean()) {
312	                this.builder.append(.latin1, "true");
313	            } else {
314	                this.builder.append(.latin1, "false");
315	            }
316	            return;
317	        }
318	
319	        if (unwrapped.isString()) {
320	            const value_str = try unwrapped.toBunString(global);
321	            defer value_str.deref();
322	
323	            this.appendString(value_str);
324	            return;
325	        }
326	
327	        if (comptime Environment.ci_assert) {
328	            bun.assertWithLocation(unwrapped.isObject(), @src());
329	        }
330	
331	        const has_anchor: ?*AnchorAlias = has_anchor: {
332	            const anchor = this.known_collections.getPtr(unwrapped) orelse {
333	                break :has_anchor null;
334	            };
335	
336	            if (!anchor.used) {
337	                break :has_anchor null;
338	            }
339	
340	            break :has_anchor anchor;
341	        };
342	
343	        if (has_anchor) |anchor| {
344	            this.builder.append(.lchar, if (anchor.anchored) '*' else '&');
345	
346	            switch (anchor.name) {
347	                .root => {
348	                    this.builder.append(.latin1, "root");
349	                },
350	                .array_item => {
351	                    this.builder.append(.latin1, "item");
352	                    this.builder.append(.usize, anchor.name.array_item);
353	                },
354	                .prop_value => |prop_value| {
355	                    if (prop_value.prop_name.length() == 0) {
356	                        this.builder.append(.latin1, "value");
357	                        this.builder.append(.usize, prop_value.counter);
358	                    } else {
359	                        this.builder.append(.string, anchor.name.prop_value.prop_name);
360	                        if (anchor.name.prop_value.counter != 0) {
361	                            this.builder.append(.usize, anchor.name.prop_value.counter);
362	                        }
363	                    }
364	                },
365	            }
366	
367	            if (anchor.anchored) {
368	                return;
369	            }
370	
371	            switch (this.space) {
372	                .minified => {
373	                    this.builder.append(.lchar, ' ');
374	                },
375	                .number, .str => {
376	                    this.newline();
377	                },
378	            }
379	            anchor.anchored = true;
380	        }
381	
382	        if (unwrapped.isArray()) {
383	            var iter = try unwrapped.arrayIterator(global);
384	
385	            if (iter.len == 0) {
386	                this.builder.append(.latin1, "[]");
387	                return;
388	            }
389	
390	            switch (this.space) {
391	                .minified => {
392	                    this.builder.append(.lchar, '[');
393	                    var first = true;
394	                    while (try iter.next()) |item| {
395	                        if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
396	                            continue;
397	                        }
398	
399	                        if (!first) {
400	                            this.builder.append(.lchar, ',');
401	                        }
402	                        first = false;
403	
404	                        try this.stringify(global, item);
405	                    }
406	                    this.builder.append(.lchar, ']');
407	                },
408	                .number, .str => {
409	                    this.builder.ensureUnusedCapacity(iter.len * "- ".len);
410	                    var first = true;
411	                    while (try iter.next()) |item| {
412	                        if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
413	                            continue;
414	                        }
415	
416	                        if (!first) {
417	                            this.newline();
418	                        }
419	                        first = false;
420	
421	                        this.builder.append(.latin1, "- ");
422	
423	                        // don't need to print a newline here for any value
424	
425	                        this.indent += 1;
426	                        try this.stringify(global, item);
427	                        this.indent -= 1;
428	                    }
429	                },
430	            }
431	
432	            return;
433	        }
434	
435	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
436	            global,
437	            try unwrapped.toObject(global),
438	        );
439	        defer iter.deinit();
440	
441	        if (iter.len == 0) {
442	            this.builder.append(.latin1, "{}");
443	            return;
444	        }
445	
446	        switch (this.space) {
447	            .minified => {
448	                this.builder.append(.lchar, '{');
449	                var first = true;
450	                while (try iter.next()) |prop_name| {
451	                    if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
452	                        continue;
453	                    }
454	
455	                    if (!first) {
456	                        this.builder.append(.lchar, ',');
457	                    }
458	                    first = false;
459	
460	                    this.appendString(prop_name);
461	                    this.builder.append(.latin1, ": ");
462	
463	                    try this.stringify(global, iter.value);
464	                }
465	                this.builder.append(.lchar, '}');
466	            },
467	            .number, .str => {
468	                this.builder.ensureUnusedCapacity(iter.len * ": ".len);
469	
470	                var first = true;
471	                while (try iter.next()) |prop_name| {
472	                    if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
473	                        continue;
474	                    }
475	
476	                    if (!first) {
477	                        this.newline();
478	                    }
479	                    first = false;
480	
481	                    this.appendString(prop_name);
482	                    this.builder.append(.latin1, ": ");
483	
484	                    this.indent += 1;
485	
486	                    if (propValueNeedsNewline(iter.value)) {
487	                        this.newline();
488	                    }
489	
490	                    try this.stringify(global, iter.value);
491	                    this.indent -= 1;
492	                }
493	                if (first) {
494	                    this.builder.append(.latin1, "{}");
495	                }
496	            },
497	        }
498	    }
