214	pub fn shellEscape(globalThis: *jsc.JSGlobalObject, callframe: *jsc.CallFrame) bun.JSError!jsc.JSValue {
215	    const arguments = callframe.arguments_old(1);
216	    if (arguments.len < 1) {
217	        return globalThis.throw("shell escape expected at least 1 argument", .{});
218	    }
219	
220	    const jsval = arguments.ptr[0];
221	    const bunstr = try jsval.toBunString(globalThis);
222	    if (globalThis.hasException()) return .zero;
223	    defer bunstr.deref();
224	
225	    var outbuf = std.array_list.Managed(u8).init(bun.default_allocator);
226	    defer outbuf.deinit();
227	
228	    if (bun.shell.needsEscapeBunstr(bunstr)) {
229	        const result = try bun.shell.escapeBunStr(bunstr, &outbuf, true);
230	        if (!result) {
231	            return globalThis.throw("String has invalid utf-16: {s}", .{bunstr.byteSlice()});
232	        }
233	        var str = bun.String.cloneUTF8(outbuf.items[0..]);
234	        return str.transferToJS(globalThis);
235	    }
236	
237	    return jsval;
238	}
