388	fn exprToJS(expr: Expr, global: *jsc.JSGlobalObject) bun.JSError!jsc.JSValue {
389	    switch (expr.data) {
390	        .e_null => return .null,
391	        .e_boolean => |boolean| return .jsBoolean(boolean.value),
392	        .e_number => |number| return .jsNumber(number.value),
393	        .e_string => |str| {
394	            return str.toJS(bun.default_allocator, global);
395	        },
396	        .e_array => |arr| {
397	            var js_arr = try JSValue.createEmptyArray(global, arr.items.len);
398	            for (arr.slice(), 0..) |item, _i| {
399	                const i: u32 = @intCast(_i);
400	                const value = try exprToJS(item, global);
401	                try js_arr.putIndex(global, i, value);
402	            }
403	            return js_arr;
404	        },
405	        .e_object => |obj| {
406	            var js_obj = JSValue.createEmptyObject(global, obj.properties.len);
407	            for (obj.properties.slice()) |prop| {
408	                const key_expr = prop.key.?;
409	                const value = try exprToJS(prop.value.?, global);
410	                const key_js = try exprToJS(key_expr, global);
411	                const key_str = try key_js.toBunString(global);
412	                defer key_str.deref();
413	                try js_obj.putMayBeIndex(global, &key_str, value);
414	            }
415	            return js_obj;
416	        },
417	        else => return .js_undefined,
418	    }
419	}
