# Plan: Add `Bun.INI` Namespace

## Context

Bun exposes format-parsing namespaces (`Bun.TOML`, `Bun.YAML`, `Bun.JSON5`, `Bun.JSONC`) as public APIs. This plan adds `Bun.INI` with `parse` and `stringify` methods following the identical architectural pattern. An INI parser already exists in `src/ini.zig` (used internally for `.npmrc`/dotenv config parsing); we will reuse it for `parse`. The `stringify` direction (JS object → INI string) needs a new implementation in `INIObject.zig`.

---

## Architecture Overview (existing pattern)

```
JS: Bun.INI.parse(str)
  → JSC lazy-property callback (C++)  BunObject_lazyPropCb_wrap_INI
  → Zig getter:                        BunObject.getINIObject()
  → creates JS object:                 INIObject.create(globalThis)
  → JS fn call:                        INIObject.parse() / INIObject.stringify()
```

---

## Files to Create

### 1. `src/bun.js/api/INIObject.zig` *(new)*

```zig
pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(globalThis, ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}));
    object.put(globalThis, ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}));
    return object;
}
```

**`parse` function** — mirrors `IniTestingAPIs.parse` in `src/ini.zig`, with proper argument validation:
1. Check argument count / null guard (like `TOMLObject.parse` does)
2. Convert arg to UTF-8 slice via `toBunString` + `toUTF8`
3. Call `bun.ini.Parser.init(bun.default_allocator, "<src>", utf8_slice, globalThis.bunVM().transpiler.env)`
4. Call `parser.parse(parser.arena.allocator())`; wrap OOM with `bun.handleOom`
5. Return `parser.out.toJS(bun.default_allocator, globalThis)` (same as `IniTestingAPIs.parse`)
6. `defer parser.deinit()`

Note: `bun.ini` is accessible via `bun.ini.Parser` because `src/bun.zig` exports `pub const ini = @import("./ini.zig")`.

**`stringify` function** — new implementation using a `Stringifier` struct:
- Accepts 1 argument: a JS object
- Validates it is an object (not null/undefined/primitive)
- Uses `bun.AllocationScope` + `std.ArrayList(u8)` as output buffer
- Calls `Stringifier.emit(global, obj, null, &buf)` which recursively:
  1. **First pass**: emit top-level simple (non-object, non-array) key=value pairs, and arrays as `key[]=value` lines
  2. **Second pass**: collect nested-object entries, emit each as `\n[section]\n` followed by inner key=value pairs (recursing with the section name as prefix for deeper nesting, yielding `[a.b.c]` headers)
- Value encoding rules:
  - `null` → `null`
  - `true`/`false` → `true`/`false`
  - numbers → decimal string
  - strings → raw if safe; wrapped in `"..."` if containing `;`, `#`, leading/trailing whitespace, or `\n`
  - arrays → one `key[]=value` line per element (nested objects inside arrays are stringified as JSON)
  - functions/symbols/undefined → skip that key
- Returns JS string via `bun.String.createUTF8ForJS(globalThis, buf.items)`

**Imports at bottom of file** (Zig convention: imports go at bottom):
```zig
const bun = @import("bun");
const default_allocator = bun.default_allocator;
const jsc = bun.jsc;
const JSError = bun.JSError;
const JSGlobalObject = jsc.JSGlobalObject;
const JSValue = jsc.JSValue;
const ZigString = jsc.ZigString;
const IniParser = bun.ini.Parser;
```

---

## Files to Modify

### 2. `src/bun.js/api.zig`

Add one line alongside the other format objects (around line 34):
```zig
pub const INIObject = @import("./api/INIObject.zig");
```

### 3. `src/bun.js/api/BunObject.zig`

**a) Lazy property callback** (inside `pub const BunObject = struct`, around line 70, grouped with other format namespaces):
```zig
pub const INI = toJSLazyPropertyCallback(Bun.getINIObject);
```

**b) Export in `exportAll()`** (around line 140, after the YAML export):
```zig
@export(&BunObject.INI, .{ .name = lazyPropertyCallbackName("INI") });
```

**c) Getter function** (around line 1289, after `getYAMLObject`):
```zig
pub fn getINIObject(globalThis: *jsc.JSGlobalObject, _: *jsc.JSObject) jsc.JSValue {
    return INIObject.create(globalThis);
}
```

**d) Import alias** (around line 2083, alongside the other format object imports):
```zig
const INIObject = bun.api.INIObject;
```

### 4. `src/bun.js/bindings/BunObject+exports.h`

Add `macro(INI)` inside `FOR_EACH_GETTER` (alphabetically near JSONC — `INI` sorts before `JSONC`):
```cpp
#define FOR_EACH_GETTER(macro) \
    ...
    macro(INI) \         // ← add here, before JSON5
    macro(JSON5) \
    macro(JSONC) \
    ...
```

### 5. `src/bun.js/bindings/BunObject.cpp`

Add one row to the `@begin bunObjectTable` table, grouped with the other format parsers (after YAML, around line 968):
```
INI    BunObject_lazyPropCb_wrap_INI    DontDelete|PropertyCallback
```

### 6. `packages/bun-types/bun.d.ts`

Add a new `namespace INI` block near the other format namespaces (e.g., after the `YAML` namespace, around line 918):

```typescript
/**
 * INI related APIs
 */
namespace INI {
  /**
   * Parse an INI string into a JavaScript object.
   *
   * Supports sections (`[section]`, `[section.sub]`), key=value pairs,
   * comment lines starting with `;` or `#`, and array values (`key[]=val`).
   *
   * @category Utilities
   *
   * @param input The INI string to parse
   * @returns A JavaScript object
   *
   * @example
   * ```ts
   * Bun.INI.parse("[foo]\nbar=baz") // { foo: { bar: "baz" } }
   * ```
   */
  export function parse(input: string): object;

  /**
   * Serialize a JavaScript object to an INI string.
   *
   * Nested objects become section headers (`[section.key]`).
   * Arrays become repeated `key[]=value` lines.
   *
   * @category Utilities
   *
   * @param input The object to stringify
   * @returns An INI-formatted string
   *
   * @example
   * ```ts
   * Bun.INI.stringify({ foo: { bar: "baz" } }) // "[foo]\nbar=baz\n"
   * ```
   */
  export function stringify(input: object): string;
}
```

---

## Files to Create (Tests)

### 7. `test/js/bun/ini/Bun.INI.test.ts` *(new)*

```typescript
import { describe, expect, test } from "bun:test";

describe("Bun.INI.parse", () => {
  test("basic key=value", () => {
    expect(Bun.INI.parse("foo=bar")).toEqual({ foo: "bar" });
  });

  test("sections become nested objects", () => {
    expect(Bun.INI.parse("[a.b]\nkey=val")).toEqual({ a: { b: { key: "val" } } });
  });

  test("comments are ignored (; and #)", () => {
    expect(Bun.INI.parse("; comment\n# comment\nkey=value")).toEqual({ key: "value" });
  });

  test("boolean coercion", () => {
    expect(Bun.INI.parse("a=true\nb=false\nc=null")).toEqual({ a: true, b: false, c: null });
  });

  test("arrays with []", () => {
    expect(Bun.INI.parse("x[]=1\nx[]=2")).toEqual({ x: ["1", "2"] });
  });

  test("throws on non-string input", () => {
    expect(() => Bun.INI.parse(null as any)).toThrow();
  });
});

describe("Bun.INI.stringify", () => {
  test("basic key=value", () => {
    expect(Bun.INI.stringify({ foo: "bar" })).toContain("foo=bar");
  });

  test("nested objects become sections", () => {
    const out = Bun.INI.stringify({ a: { b: { key: "val" } } });
    expect(out).toContain("[a.b]");
    expect(out).toContain("key=val");
  });

  test("arrays use key[]= syntax", () => {
    const out = Bun.INI.stringify({ x: ["1", "2"] });
    expect(out).toContain("x[]=1");
    expect(out).toContain("x[]=2");
  });

  test("booleans and null", () => {
    const out = Bun.INI.stringify({ a: true, b: false, c: null });
    expect(out).toContain("a=true");
    expect(out).toContain("b=false");
    expect(out).toContain("c=null");
  });

  test("round-trips through parse/stringify/parse", () => {
    const original = { server: { host: "localhost", port: "8080" }, debug: true };
    const reparsed = Bun.INI.parse(Bun.INI.stringify(original));
    expect(reparsed).toEqual(original);
  });
});
```

---

## Critical Existing Files (reference only)

| File | Role |
|------|------|
| `src/ini.zig` | INI `Parser` struct — reused for `parse()` |
| `src/bun.js/api/TOMLObject.zig` | Template for `parse()` function |
| `src/bun.js/api/YAMLObject.zig` | Template for `stringify()` with `Stringifier` struct |
| `src/bun.js/api/BunObject.zig` | Lazy property registration pattern |
