379	            anchor.anchored = true;
380	        }
381	
382	        if (unwrapped.isArray()) {
383	            var iter = try unwrapped.arrayIterator(global);
384	
385	            if (iter.len == 0) {
386	                this.builder.append(.latin1, "[]");
387	                return;
388	            }
389	
390	            switch (this.space) {
