315	    fn appendKey(this: *Stringifier, name: bun.String) void {
316	        const is_identifier = is_identifier: {
317	            if (name.length() == 0) break :is_identifier false;
318	            if (!bun.js_lexer.isIdentifierStart(@intCast(name.charAt(0)))) break :is_identifier false;
319	            for (1..name.length()) |i| {
320	                if (!bun.js_lexer.isIdentifierContinue(@intCast(name.charAt(i)))) break :is_identifier false;
321	            }
322	            break :is_identifier true;
323	        };
324	
325	        if (is_identifier) {
326	            this.builder.append(.string, name);
327	        } else {
328	            this.appendQuotedString(name);
329	        }
330	    }
331	
332	    fn appendQuotedString(this: *Stringifier, str: bun.String) void {
333	        this.builder.append(.lchar, '\'');
334	        for (0..str.length()) |i| {
335	            const c = str.charAt(i);
336	            switch (c) {
337	                0x00 => this.builder.append(.latin1, "\\0"),
338	                0x08 => this.builder.append(.latin1, "\\b"),
339	                0x09 => this.builder.append(.latin1, "\\t"),
340	                0x0a => this.builder.append(.latin1, "\\n"),
341	                0x0b => this.builder.append(.latin1, "\\v"),
342	                0x0c => this.builder.append(.latin1, "\\f"),
343	                0x0d => this.builder.append(.latin1, "\\r"),
344	                0x27 => this.builder.append(.latin1, "\\'"), // single quote
345	                0x5c => this.builder.append(.latin1, "\\\\"), // backslash
346	                0x2028 => this.builder.append(.latin1, "\\u2028"),
347	                0x2029 => this.builder.append(.latin1, "\\u2029"),
348	                0x01...0x07, 0x0e...0x1f, 0x7f => {
349	                    // Other control chars → \xHH
350	                    this.builder.append(.latin1, "\\x");
351	                    this.builder.append(.lchar, hexDigit(c >> 4));
352	                    this.builder.append(.lchar, hexDigit(c & 0x0f));
353	                },
354	                else => this.builder.append(.uchar, c),
355	            }
356	        }
357	        this.builder.append(.lchar, '\'');
358	    }
359	
360	    fn hexDigit(v: u16) u8 {
361	        const nibble: u8 = @intCast(v & 0x0f);
362	        return if (nibble < 10) '0' + nibble else 'a' + nibble - 10;
363	    }
364	
365	    fn newline(this: *Stringifier) void {
366	        switch (this.space) {
367	            .minified => {},
368	            .number => |space_num| {
369	                this.builder.append(.lchar, '\n');
370	                for (0..this.indent * space_num) |_| {
371	                    this.builder.append(.lchar, ' ');
372	                }
373	            },
374	            .str => |space_str| {
375	                this.builder.append(.lchar, '\n');
376	                const clamped = if (space_str.length() > 10)
377	                    space_str.substringWithLen(0, 10)
378	                else
379	                    space_str;
380	                for (0..this.indent) |_| {
381	                    this.builder.append(.string, clamped);
382	                }
383	            },
384	        }
385	    }
386	};
