pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

/// Parse an INI-formatted string into a JS object.
///
/// Handles:
///   - `[section]` and `[dotted.section]` headers → nested objects
///   - `key = value` and `key: value` pairs
///   - `;` and `#` comment lines
///   - Inline comments after values (outside quotes)
///   - Basic type inference: `true`/`false`/`yes`/`no` → boolean,
///     integers and floats → number, `null` → null, else → string
pub fn parse(global: *jsc.JSGlobalObject, callFrame: *jsc.CallFrame) bun.JSError!jsc.JSValue {
    const input_value = callFrame.argument(0);

    if (input_value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected a string to parse", .{});
    }

    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
    defer arena.deinit();
    const allocator = arena.allocator();

    var input_str = try input_value.toBunString(global);
    defer input_str.deref();
    const input_utf8 = input_str.toUTF8(allocator);
    defer input_utf8.deinit();
    const src = input_utf8.slice();

    const root = jsc.JSValue.createEmptyObject(global, 4);

    // Map from full dotted section path to the JS object for that section.
    // Keyed by arena-allocated copies of the path strings.
    var sections: std.StringHashMapUnmanaged(jsc.JSValue) = .{};
    defer sections.deinit(allocator);
    try sections.put(allocator, "", root);

    var current_obj = root;

    var line_iter = std.mem.splitScalar(u8, src, '\n');
    while (line_iter.next()) |raw_line| {
        // Strip trailing \r for Windows line endings
        const line = if (raw_line.len > 0 and raw_line[raw_line.len - 1] == '\r')
            raw_line[0 .. raw_line.len - 1]
        else
            raw_line;

        // Trim leading whitespace
        const trimmed = std.mem.trimLeft(u8, line, " \t");
        if (trimmed.len == 0) continue;

        // Skip comment lines
        if (trimmed[0] == ';' or trimmed[0] == '#') continue;

        // Section header: [section.name]
        if (trimmed[0] == '[') {
            const close = std.mem.indexOfScalar(u8, trimmed, ']') orelse continue;
            const section_name = std.mem.trim(u8, trimmed[1..close], " \t");
            if (section_name.len == 0) continue;

            current_obj = try getOrCreateSection(global, allocator, &sections, section_name);
            continue;
        }

        // key = value  or  key: value
        const sep_idx = std.mem.indexOfAny(u8, trimmed, "=:") orelse continue;
        const key = std.mem.trim(u8, trimmed[0..sep_idx], " \t");
        if (key.len == 0) continue;

        const val_raw = std.mem.trim(u8, trimmed[sep_idx + 1 ..], " \t");
        const val_str = stripInlineComment(val_raw);

        const value = iniValueToJS(global, val_str);
        const key_bun = bun.String.borrowUTF8(key);
        try current_obj.putMayBeIndex(global, &key_bun, value);
    }

    return root;
}

/// Look up or create a nested section object by its full dotted path.
fn getOrCreateSection(
    global: *jsc.JSGlobalObject,
    allocator: std.mem.Allocator,
    sections: *std.StringHashMapUnmanaged(jsc.JSValue),
    path: []const u8,
) bun.JSError!jsc.JSValue {
    if (sections.get(path)) |existing| return existing;

    const obj = jsc.JSValue.createEmptyObject(global, 4);

    const last_dot = std.mem.lastIndexOfScalar(u8, path, '.') orelse {
        // Top-level section: put directly on root
        const root = sections.get("").?;
        const key_bun = bun.String.borrowUTF8(path);
        try root.putMayBeIndex(global, &key_bun, obj);
        const path_copy = try allocator.dupe(u8, path);
        try sections.put(allocator, path_copy, obj);
        return obj;
    };

    // Recursively ensure the parent exists, then attach the child
    const parent = try getOrCreateSection(global, allocator, sections, path[0..last_dot]);
    const child_key_bun = bun.String.borrowUTF8(path[last_dot + 1 ..]);
    try parent.putMayBeIndex(global, &child_key_bun, obj);
    const path_copy = try allocator.dupe(u8, path);
    try sections.put(allocator, path_copy, obj);
    return obj;
}

/// Strip an inline comment from a value string (after `;` or `#` outside quotes).
fn stripInlineComment(s: []const u8) []const u8 {
    var in_double: bool = false;
    var in_single: bool = false;
    var i: usize = 0;
    while (i < s.len) : (i += 1) {
        switch (s[i]) {
            '"' => if (!in_single) {
                in_double = !in_double;
            },
            '\'' => if (!in_double) {
                in_single = !in_single;
            },
            ';', '#' => if (!in_double and !in_single) {
                return std.mem.trimRight(u8, s[0..i], " \t");
            },
            else => {},
        }
    }
    return s;
}

/// Convert a raw INI value string to a JS value with basic type inference.
fn iniValueToJS(global: *jsc.JSGlobalObject, s: []const u8) jsc.JSValue {
    // Double-quoted string — strip outer quotes
    if (s.len >= 2 and s[0] == '"' and s[s.len - 1] == '"') {
        return bun.String.borrowUTF8(s[1 .. s.len - 1]).toJS(global);
    }
    // Single-quoted string — strip outer quotes
    if (s.len >= 2 and s[0] == '\'' and s[s.len - 1] == '\'') {
        return bun.String.borrowUTF8(s[1 .. s.len - 1]).toJS(global);
    }
    // null
    if (std.mem.eql(u8, s, "null") or std.mem.eql(u8, s, "NULL")) {
        return .null;
    }
    // boolean true
    if (std.mem.eql(u8, s, "true") or std.mem.eql(u8, s, "True") or std.mem.eql(u8, s, "TRUE") or
        std.mem.eql(u8, s, "yes") or std.mem.eql(u8, s, "Yes") or std.mem.eql(u8, s, "YES"))
    {
        return JSValue.jsBoolean(true);
    }
    // boolean false
    if (std.mem.eql(u8, s, "false") or std.mem.eql(u8, s, "False") or std.mem.eql(u8, s, "FALSE") or
        std.mem.eql(u8, s, "no") or std.mem.eql(u8, s, "No") or std.mem.eql(u8, s, "NO"))
    {
        return JSValue.jsBoolean(false);
    }
    // number (integer or float)
    if (std.fmt.parseFloat(f64, s)) |f| {
        return JSValue.jsNumber(f);
    } else |_| {}
    // fallback: return as string
    return bun.String.borrowUTF8(s).toJS(global);
}

/// Serialize a JS object to INI format.
///
/// Top-level scalar values are emitted as `key = value` pairs.
/// Nested objects are emitted as `[section]` headers followed by their
/// scalar properties.  Arrays and other non-scalar, non-object values
/// are silently skipped (INI has no standard representation for them).
pub fn stringify(global: *jsc.JSGlobalObject, callFrame: *jsc.CallFrame) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    if (value.isEmptyOrUndefinedOrNull()) {
        return global.throwInvalidArguments("Expected an object to stringify", .{});
    }

    if (!value.isObject() or value.isArray()) {
        return global.throwInvalidArguments("INI.stringify: input must be a plain object", .{});
    }

    var arena: bun.ArenaAllocator = .init(bun.default_allocator);
