import { describe, expect, test } from "bun:test";

describe("Bun.INI", () => {
  // ─────────────────────────────────────────────────────────────────────
  // parse — basic key/value
  // ─────────────────────────────────────────────────────────────────────
  describe("parse", () => {
    test("simple key=value pairs", () => {
      const result = Bun.INI.parse("host = localhost\nport = 8080\n");
      expect(result).toEqual({ host: "localhost", port: 8080 });
    });

    test("key: value pairs (colon separator)", () => {
      const result = Bun.INI.parse("name: Alice\nage: 30\n");
      expect(result).toEqual({ name: "Alice", age: 30 });
    });

    test("whitespace is trimmed from keys and values", () => {
      const result = Bun.INI.parse("  key  =  value  \n");
      expect(result).toEqual({ key: "value" });
    });

    test("empty input returns empty object", () => {
      expect(Bun.INI.parse("")).toEqual({});
    });

    test("only whitespace returns empty object", () => {
      expect(Bun.INI.parse("   \n  \n")).toEqual({});
    });

    // ─── Comments ────────────────────────────────────────────────────────
    test("semicolon comment lines are skipped", () => {
      const result = Bun.INI.parse("; this is a comment\nkey = value\n");
      expect(result).toEqual({ key: "value" });
    });

    test("hash comment lines are skipped", () => {
      const result = Bun.INI.parse("# another comment\nkey = value\n");
      expect(result).toEqual({ key: "value" });
    });

    test("inline ; comments are stripped from values", () => {
      const result = Bun.INI.parse("key = hello ; world\n");
      expect(result).toEqual({ key: "hello" });
    });

    test("inline # comments are stripped from values", () => {
      const result = Bun.INI.parse("key = hello # world\n");
      expect(result).toEqual({ key: "hello" });
    });

    test("inline comment not stripped inside double-quoted string", () => {
      const result = Bun.INI.parse('key = "hello ; world"\n');
      expect(result).toEqual({ key: "hello ; world" });
    });

    test("inline comment not stripped inside single-quoted string", () => {
      const result = Bun.INI.parse("key = 'hello # world'\n");
      expect(result).toEqual({ key: "hello # world" });
    });

    // ─── Type inference ───────────────────────────────────────────────────
    test("true/false are parsed as booleans", () => {
      const result = Bun.INI.parse("a = true\nb = false\n");
      expect(result).toEqual({ a: true, b: false });
    });

    test("True / FALSE / YES / no (case variants) are parsed as booleans", () => {
      const result = Bun.INI.parse("a = True\nb = FALSE\nc = YES\nd = no\n");
      expect(result).toEqual({ a: true, b: false, c: true, d: false });
    });

    test("null and NULL are parsed as null", () => {
      const result = Bun.INI.parse("a = null\nb = NULL\n");
      expect(result).toEqual({ a: null, b: null });
    });

    test("integer strings are parsed as numbers", () => {
      const result = Bun.INI.parse("x = 42\ny = -7\n");
      expect(result).toEqual({ x: 42, y: -7 });
    });

    test("float strings are parsed as numbers", () => {
      const result = Bun.INI.parse("pi = 3.14\n");
      expect((result as any).pi).toBeCloseTo(3.14);
    });

    test("non-numeric strings remain strings", () => {
      const result = Bun.INI.parse("key = hello world\n");
      expect(result).toEqual({ key: "hello world" });
    });

    test("double-quoted values have quotes stripped", () => {
      const result = Bun.INI.parse('key = "hello"\n');
      expect(result).toEqual({ key: "hello" });
    });

    test("single-quoted values have quotes stripped", () => {
      const result = Bun.INI.parse("key = 'hello'\n");
      expect(result).toEqual({ key: "hello" });
    });

    // ─── Sections ─────────────────────────────────────────────────────────
    test("[section] creates a nested object", () => {
      const result = Bun.INI.parse("[db]\nhost = localhost\nport = 5432\n");
      expect(result).toEqual({ db: { host: "localhost", port: 5432 } });
    });

    test("top-level keys appear before section keys", () => {
      const result = Bun.INI.parse("global = 1\n[section]\nlocal = 2\n");
      expect(result).toEqual({ global: 1, section: { local: 2 } });
    });

    test("multiple sections", () => {
      const result = Bun.INI.parse("[a]\nx = 1\n[b]\ny = 2\n");
      expect(result).toEqual({ a: { x: 1 }, b: { y: 2 } });
    });

    test("dotted section [a.b] creates nested objects", () => {
      const result = Bun.INI.parse("[a.b]\nkey = val\n");
      expect(result).toEqual({ a: { b: { key: "val" } } });
    });

    test("deeply dotted section [a.b.c]", () => {
      const result = Bun.INI.parse("[a.b.c]\nkey = val\n");
      expect(result).toEqual({ a: { b: { c: { key: "val" } } } });
    });

    test("[a.b] before [a] still produces a coherent tree", () => {
      const result = Bun.INI.parse("[a.b]\ndeep = yes\n[a]\nshallow = yes\n");
      expect(result).toEqual({ a: { shallow: true, b: { deep: true } } });
    });

    test("re-entering the same section appends keys", () => {
      const result = Bun.INI.parse("[s]\na = 1\n[s]\nb = 2\n");
      expect(result).toEqual({ s: { a: 1, b: 2 } });
    });

    // ─── Windows line endings ─────────────────────────────────────────────
    test("CRLF line endings are handled", () => {
      const result = Bun.INI.parse("key = value\r\n");
      expect(result).toEqual({ key: "value" });
    });

    // ─── Error handling ───────────────────────────────────────────────────
    test("throws on undefined input", () => {
      expect(() => (Bun.INI.parse as any)(undefined)).toThrow();
    });

    test("throws on null input", () => {
      expect(() => (Bun.INI.parse as any)(null)).toThrow();
    });
  });

  // ─────────────────────────────────────────────────────────────────────
  // stringify
  // ─────────────────────────────────────────────────────────────────────
  describe("stringify", () => {
    test("flat object with scalar values", () => {
      const out = Bun.INI.stringify({ host: "localhost", port: 3000 });
      expect(out).toContain("host = localhost");
      expect(out).toContain("port = 3000");
    });

    test("boolean values", () => {
      const out = Bun.INI.stringify({ enabled: true, debug: false });
      expect(out).toContain("enabled = true");
      expect(out).toContain("debug = false");
    });

    test("null values", () => {
      const out = Bun.INI.stringify({ x: null });
      expect(out).toContain("x = null");
    });

    test("nested object becomes [section] block", () => {
      const out = Bun.INI.stringify({ db: { host: "localhost" } });
      expect(out).toContain("[db]");
      expect(out).toContain("host = localhost");
    });

    test("deeply nested object uses dotted section path", () => {
      const out = Bun.INI.stringify({ a: { b: { key: "val" } } });
      expect(out).toContain("[a.b]");
      expect(out).toContain("key = val");
    });

    test("top-level scalars appear before sections", () => {
      const out = Bun.INI.stringify({ global: 1, section: { local: 2 } });
      const globalIdx = out.indexOf("global = 1");
      const sectionIdx = out.indexOf("[section]");
      expect(globalIdx).toBeGreaterThanOrEqual(0);
      expect(sectionIdx).toBeGreaterThan(globalIdx);
    });

    test("string values needing quotes are double-quoted", () => {
      const out = Bun.INI.stringify({ comment: "hello ; world" });
      // The `;` forces quoting
      expect(out).toContain('"hello ; world"');
    });

    test("empty string is double-quoted", () => {
      const out = Bun.INI.stringify({ key: "" });
      expect(out).toContain('key = ""');
    });

    test("throws on non-object input", () => {
      expect(() => (Bun.INI.stringify as any)("string")).toThrow();
      expect(() => (Bun.INI.stringify as any)(42)).toThrow();
      expect(() => (Bun.INI.stringify as any)([])).toThrow();
    });

    test("throws on undefined input", () => {
      expect(() => (Bun.INI.stringify as any)(undefined)).toThrow();
    });
  });

  // ─────────────────────────────────────────────────────────────────────
  // Round-trip: stringify → parse should recover the original object
  // ─────────────────────────────────────────────────────────────────────
  describe("round-trip", () => {
    test("flat object", () => {
      const original = { host: "localhost", port: 3000, debug: true };
      const parsed = Bun.INI.parse(Bun.INI.stringify(original));
      expect(parsed).toEqual(original);
    });

    test("nested object", () => {
      const original = {
        app: "myapp",
        db: { host: "localhost", port: 5432, enabled: true },
      };
      const parsed = Bun.INI.parse(Bun.INI.stringify(original));
      expect(parsed).toEqual(original);
    });

    test("deeply nested object", () => {
      const original = { a: { b: { c: { key: "value", num: 42 } } } };
      const parsed = Bun.INI.parse(Bun.INI.stringify(original));
      expect(parsed).toEqual(original);
    });

    test("null values survive round-trip", () => {
      const original = { x: null };
      const parsed = Bun.INI.parse(Bun.INI.stringify(original));
      expect(parsed).toEqual(original);
    });
  });
});

